{{(() => { const tableData = Renewal_List.processedTableData || []; return tableData.length > 0 ? tableData.map((currentRow, currentIndex) => (
(() => {
  // Renewal-Status prüfen: alles außer "not_renewed" gilt als renewed -> Closed Won
  const renewalRaw = (currentRow.renewal_status ?? "").toString().trim().toLowerCase();
  const isRenewed = renewalRaw && renewalRaw !== "not_renewed";

  if (isRenewed) {
    return "#22b31e"; // Closed Won (dunkelgrün)
  }

  // Sonst: hole den neuesten Risk-Status für diese opp_id
  const data = Array.isArray(GetCurrentRiskStatus.data) ? GetCurrentRiskStatus.data : [];
  const oppData = data
    .filter(item => item.opp_id === currentRow.opportunity_id)
    .sort((a, b) => new Date(b.submit_timestamp) - new Date(a.submit_timestamp));

  const status = oppData?.[0]?.risk_status;
  if (!status) return "transparent";

  switch (status) {
    case "At Risk":
      return "#e53935";  // Rot
    case "Low Risk":
      return "#AEEA00";  // Lime (hellgrün, klarer Unterschied zu Closed Won)
    case "Closed Won":
      return "#22b31e";  // Dunkelgrün
    case "Renewal Lost":
      return "#424242";  // Dunkelgrau
    default:
      return "transparent";
  }
})()
)) : 
