customColumn2.computedValue:
{{(() => { const tableData = Renewal_List.processedTableData || []; return tableData.length > 0 ? tableData.map((currentRow, currentIndex) => (
  (() => {
    if (currentRow["renewal_status"] !== "not_renewed") {
      return "";
    }

    const expiry = moment(currentRow["contract_expired_date"]);
    const today = moment();
    const daysLeft = expiry.diff(today, 'days');

    const lastUpdate = GetCurrentRiskStatus.data?.find(
      r => r.opp_id === currentRow["opportunity_id"]
    );

    const lastSubmit = lastUpdate ? moment(lastUpdate.submit_timestamp) : null;
    const interval = daysLeft >= 180 ? 180 : daysLeft >= 90 ? 30 : 14;

    if (!lastSubmit) {
      if (daysLeft <= 180) return "🔔 Update";
      return ""; // Leeres Feld wenn noch > 180 Tage
    }

    const nextDue = lastSubmit.clone().add(interval, 'days');
    const daysToUpdate = nextDue.diff(today, 'days');

    return daysToUpdate <= 0 ? "🔔 Update" : `noch ${daysToUpdate} d`;
  })()
)) : 
