customColumn3.computedValue:
{{(() => { const tableData = Renewal_List.processedTableData || []; return tableData.length > 0 ? tableData.map((currentRow, currentIndex) => (
(() => {
  const data = Array.isArray(GetCurrentRiskStatus.data) ? GetCurrentRiskStatus.data : [];
  const oppData = data
    .filter(item => item.opp_id === currentRow.opportunity_id)
    .sort((a, b) => new Date(b.submit_timestamp) - new Date(a.submit_timestamp))
    .slice(0, 4);

  const statusColor = (status) => {
    switch (status) {
      case "At Risk": return "#ea4335";       // rot
      case "Low Risk": return "#AEEA00";      // hellgrün
      case "Closed Won": return "#22b31e";    // grün
      case "Renewal Lost": return "#424242";  // dunkelgrau/schwarz
      default: return "#ededed";              // hellgrau
    }
  };

  const getTrend = () => {
    if (oppData.length < 2) return "";
    const statusValues = { "Closed Won": 4, "Low Risk": 3, "At Risk": 2, "Renewal Lost": 1 };
    const current = statusValues[oppData[0]?.risk_status] || 0;
    const previous = statusValues[oppData[1]?.risk_status] || 0;
    if (current > previous) return "↑";
    if (current < previous) return "↓";
    return "→";
  };

  const dotSize = 12;        // kleiner: 16 → 12
  const dotGap = 6;          // kleiner: 8 → 6
  const lineHeight = 18;     // kleiner: 22 → 18

  const dots = [];
  for (let i = 0; i < 4; i++) {
    const color = oppData[i] ? statusColor(oppData[i].risk_status) : statusColor(undefined);
    dots.push(
      `<span
         title="${oppData[i]?.risk_status ?? 'Unknown'}"
         style="
           display:inline-block;
           width:${dotSize}px;
           height:${dotSize}px;
           border-radius:50%;
           background:${color};
           margin-left:${i === 0 ? 0 : dotGap}px;
           vertical-align:middle;
         ">
       </span>`
    );
  }

  const trend = getTrend();

  return `
    <div style="
      display:flex;
      align-items:center;
      width:100%;
      height:${lineHeight}px;
      line-height:${lineHeight}px;
      font-size:12px;
    ">
      <span style="flex:0 0 auto; text-align:left; min-width:1.2em;">${trend}</span>
      <span style="flex:1 1 auto; text-align:right; height:100%; line-height:${lineHeight}px;">
        ${dots.join("")}
      </span>
    </div>
  `;
})()
)) : 
